commits.content:
import React, { useState, useEffect } from 'react';
import api from '../../utils/api';
import { FiDollarSign, FiShoppingBag, FiUsers, FiAlertCircle, FiCalendar, FiTrendingUp } from 'react-icons/fi';
import { Link } from 'react-router-dom';

const AdminDashboard = () => {
  const [stats, setStats] = useState({
    todaySales: 0,
    todayTransactions: 0,
    monthSales: 0,
    totalCashiers: 0,
    topCashier: null,
    lowStock: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const res = await api.get('/admin/stats');
      setStats(res.data);
    } catch (error) {
      console.error('Error fetching admin stats:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="text-center py-20">Loading...</div>;

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-gray-800">Admin Dashboard</h1>

      {/* بطاقات الإحصائيات */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white rounded-xl shadow-md p-6 flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center text-blue-600">
            <FiDollarSign size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500">Today's Sales</p>
            <p className="text-2xl font-bold">${stats.todaySales.toFixed(2)}</p>
          </div>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6 flex items-center gap-4">
          <div className="w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center text-green-600">
            <FiShoppingBag size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500">Today's Transactions</p>
            <p className="text-2xl font-bold">{stats.todayTransactions}</p>
          </div>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6 flex items-center gap-4">
          <div className="w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center text-purple-600">
            <FiCalendar size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500">Month Sales</p>
            <p className="text-2xl font-bold">${stats.monthSales.toFixed(2)}</p>
          </div>
        </div>
        <div className="bg-white rounded-xl shadow-md p-6 flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-100 rounded-lg flex items-center justify-center text-indigo-600">
            <FiUsers size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500">Total Cashiers</p>
            <p className="text-2xl font-bold">{stats.totalCashiers}</p>
          </div>
        </div>
      </div>

      {/* بطاقة أفضل كاشير اليوم */}
      {stats.topCashier && (
        <div className="bg-white rounded-xl shadow-md p-6">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <FiTrendingUp className="text-blue-600" />
            Top Cashier Today
          </h2>
          <div className="flex items-center justify-between">
            <div>
              <p className="text-xl font-bold">{stats.topCashier.cashier_name}</p>
              <p className="text-gray-600">Transactions: {stats.topCashier.transactions}</p>
              <p className="text-gray-600">Total Sales: ${stats.topCashier.total?.toFixed(2)}</p>
            </div>
            <Link to={`/admin/cashiers`} className="btn-outline text-sm">View Details</Link>
          </div>
        </div>
      )}

      {/* إنذار المخزون المنخفض */}
      {stats.lowStock > 0 && (
        <div className="bg-red-50 border border-red-200 rounded-xl p-4 flex items-center gap-3">
          <FiAlertCircle className="text-red-600 flex-shrink-0" size={24} />
          <p className="text-red-800">
            <span className="font-bold">{stats.lowStock}</span> products are low on stock.
            <Link to="/inventory" className="underline ml-2">View Inventory</Link>
          </p>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
